#include <iostream>
using namespace std;

// Функція змінює змінні через покажчики! 
// Ми передаємо АДРЕСИ (int* pa) і змінюємо оригінали через зірочку (*pa).
void pushMoney(int* target, int amount) {
    // Йдемо за адресою цілі і додаємо amount до того, що там лежить
    *target = *target + amount; 
}

int main() {
    int chest = 42;             // Сейф з 42 монетами
    int* ptr = &chest;          // Покажчик, зберігає АДРЕСУ chest

    cout << "В сейфі лежить: " << chest << " монет." << endl;
    cout << "Адреса сейфа в RAM: " << &chest << endl;
    cout << "Покажчик ptr містить: " << ptr << endl;

    // Розіменування: дивимось що там лежить
    cout << "Через покажчик можна змінити: *ptr = 100!" << endl;
    *ptr = 100;

    cout << "Тепер в сейфі: " << chest << " монет." << endl; // Змінився оригінал!

    cout << "
---- Функції та Покажчики ----" << endl;
    int wallet = 50;
    cout << "Гаманець до виклику: " << wallet << endl;

    // Передаємо АДРЕСУ гаманця, а не його копію
    pushMoney(&wallet, 500);

    cout << "Гаманець після: " << wallet << endl;

    int* safePtr = nullptr; // Правильна звичка

    return 0;
}
